export const widgetCss = ":root{--lightningcss-light:initial;--lightningcss-dark: ;color-scheme:light dark;--qc-bg:#f5efe4;--qc-panel:#fffcf7d1;--qc-panel-strong:#fffcf7f0;--qc-text:#241b16;--qc-muted:#6a5a51;--qc-line:#3623141f;--qc-accent:#0f766e;--qc-accent-strong:#115e59;--qc-warm:#d6a662;font-family:Aptos,Segoe UI,sans-serif}@media (prefers-color-scheme:dark){:root{--lightningcss-light: ;--lightningcss-dark:initial}}*{box-sizing:border-box}body{color:var(--qc-text);background:radial-gradient(circle at 0 0,#d6a66252,#0000 34%),linear-gradient(#f8f4eb 0%,#f1e7d7 100%);margin:0}button,input,select{font:inherit}.app-shell{gap:18px;padding:20px;display:grid}.hero-card,.form-card,.result-card,.panel,.empty-panel{background:var(--qc-panel);-webkit-backdrop-filter:blur(18px);backdrop-filter:blur(18px);border:1px solid var(--qc-line);border-radius:24px;padding:20px;box-shadow:0 16px 40px #32201114}.hero-card{justify-content:space-between;align-items:flex-start;gap:16px;display:flex}.hero-card h1,.form-card h1,.result-card h2,.panel h3,.empty-panel h2{letter-spacing:-.03em;margin:0;font-family:Iowan Old Style,Palatino Linotype,Georgia,serif}.hero-copy,.muted,.line-item p,.preset-card p,.empty-panel p{color:var(--qc-muted)}.eyebrow,.preset-label{color:var(--qc-accent-strong);letter-spacing:.12em;text-transform:uppercase;margin:0 0 8px;font-size:12px;font-weight:700}.connection-badge,.status-chip,.estimate-pill{color:var(--qc-accent-strong);white-space:nowrap;background:#0f766e1f;border-radius:999px;padding:10px 14px;font-weight:700}.preset-strip{grid-template-columns:repeat(3,minmax(0,1fr));gap:12px;display:grid}.preset-card{background:var(--qc-panel-strong);border:1px solid var(--qc-line);text-align:left;cursor:pointer;border-radius:18px;padding:16px;transition:transform .15s,box-shadow .15s,border-color .15s}.preset-card:hover{border-color:#0f766e3d;transform:translateY(-2px);box-shadow:0 14px 28px #241b1614}.preset-card strong{margin-bottom:6px;display:block}.form-card-header,.panel-header,.result-header,.action-row,.line-item{justify-content:space-between;align-items:flex-start;gap:12px;display:flex}.form-grid,.estimate-grid,.extras-grid,.results-stack{gap:12px;display:grid}.form-grid{grid-template-columns:repeat(2,minmax(0,1fr));margin-top:16px}.form-grid label,.form-grid input,.form-grid select{width:100%}.form-grid label span{margin-bottom:8px;font-size:14px;font-weight:600;display:block}.form-grid input,.form-grid select{border:1px solid var(--qc-line);color:var(--qc-text);background:#ffffffbf;border-radius:14px;padding:12px 14px}.panel{margin-top:14px}.extras-grid{grid-template-columns:repeat(2,minmax(0,1fr))}.extra-chip{border:1px solid var(--qc-line);background:#ffffffc7;border-radius:16px;align-items:center;gap:10px;padding:12px 14px;display:flex}.extra-chip.selected{background:#0f766e14;border-color:#0f766e61}.action-row{flex-wrap:wrap;align-items:center;margin-top:18px}.primary-button,.secondary-button{cursor:pointer;border:none;border-radius:999px;padding:12px 18px;font-weight:700}.primary-button{background:linear-gradient(135deg, var(--qc-accent) 0%, #1d4d4a 100%);color:#fff}.secondary-button{color:var(--qc-accent-strong);background:#115e5917}.primary-button:disabled,.secondary-button:disabled{opacity:.6;cursor:not-allowed}.inline-note{color:var(--qc-muted);font-size:14px}.error-banner{color:#7f1d1d;background:#be292914;border:1px solid #a5242429;border-radius:18px;padding:14px 16px}.results-stack{grid-template-columns:1.6fr 1fr}.result-card{gap:14px;display:grid}.estimate-grid{grid-template-columns:repeat(3,minmax(0,1fr))}.estimate-grid div{border:1px solid var(--qc-line);background:#ffffffc2;border-radius:16px;padding:14px}.estimate-grid span{color:var(--qc-muted);margin-bottom:6px;font-size:13px;display:block}.estimate-grid strong{font-size:20px}.line-items{gap:10px;display:grid}.line-item{border-top:1px solid var(--qc-line);padding-top:10px}.line-item:first-child{border-top:none;padding-top:0}.line-item strong{margin-bottom:4px;display:block}.bullet-list{gap:8px;margin:0;padding-left:18px;display:grid}.client-copy{margin:0;line-height:1.7}.empty-state{color:var(--qc-muted);margin:0}.empty-panel{text-align:center}@media (width<=820px){.preset-strip,.form-grid,.extras-grid,.estimate-grid,.results-stack{grid-template-columns:1fr}.hero-card,.form-card-header,.result-header{flex-direction:column}}\n";
